from datetime import datetime, timedelta
from meteostat import Point, Daily, Stations
from geopy.geocoders import Nominatim

geolocator = Nominatim(user_agent="jarvis_climate_bot")

def get_local_weather(city):

    location = geolocator.geocode(city)
    if not location:
        return None, None

    start = datetime.now() - timedelta(days=120)
    end = datetime.now()

    stations = Stations()
    stations = stations.nearby(location.latitude, location.longitude)
    stations = stations.inventory('daily', start)
    station = stations.fetch(3)

    if station.empty:
        return None, None

    for station_id in station.index:
        try:
            data = Daily(station_id, start, end).fetch()
            if not data.empty and 'tavg' in data.columns:
                data = data.ffill()
                return data, data['tavg'].values.reshape(-1, 1)
        except:
            continue

    return None, None

import numpy as np
from geopy.distance import geodesic

def generate_adaptive_india_grid():
    coords = []
    for lat in np.arange(8, 37, 5):
        for lon in np.arange(68, 97, 5):
            coords.append((lat, lon))
    return coords

def build_adaptive_adjacency(coords, base_coupling=0.03):
    n = len(coords)
    A = np.zeros((n, n))

    for i in range(n):
        for j in range(n):
            if i != j:
                dist = geodesic(coords[i], coords[j]).km
                weight = base_coupling * np.exp(-dist / 800)
                A[i, j] = weight

    return A

def normalize_adjacency(A):
    D = np.diag(np.sum(A, axis=1))
    D_inv_sqrt = np.linalg.inv(np.sqrt(D + 1e-8))
    A_norm = D_inv_sqrt @ A @ D_inv_sqrt
    return A_norm

def apply_spatial_diffusion_to_temp(base_temp_series, adjacency):

    n_nodes = adjacency.shape[0]
    spatial_temp = np.tile(base_temp_series.reshape(-1, 1), (1, n_nodes))

    for t in range(len(spatial_temp)):
        current = spatial_temp[t]
        new_vals = current.copy()

        for i in range(n_nodes):
            exchange = 0
            for j in range(n_nodes):
                if i != j:
                    exchange += adjacency[i, j] * (current[j] - current[i])
            new_vals[i] += exchange

        spatial_temp[t] = new_vals

    return spatial_temp

import speech_recognition as sr

def listen_mic():
    r = sr.Recognizer()
    with sr.Microphone() as source:
        print("\n[MIC ACTIVE] Listening...")
        r.adjust_for_ambient_noise(source)
        try:
            audio = r.listen(source, timeout=5)
            return r.recognize_google(audio).lower()
        except:
            return None

def get_user_input():
    print("\n[INPUT] Press Enter to Speak, or type command:")
    user_in = input(">>> ").strip().lower()
    if user_in == "":
        return listen_mic()
    return user_in
